// ─────────────────────────────────────────────
// VHSYS :: employers_plus
// Rota   : POST /employers_plus
// Fase 4 : Fluxo EMPLOYERS
// ─────────────────────────────────────────────
// Input  : { xml_ref: '<![CDATA[<html>...</html>]]>' }
// Output : { message: '...', ids: [{codigo:'...'}, ...] } HTTP 200
// Banco  : NENHUM — apenas extrai códigos do HTML
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.xml_ref) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: xml_ref' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route    : 'employers_plus',
  event    : 'input_validated',
  level    : 'info'
}));

return { _valid: true, xml_ref: body.xml_ref };

// ─────────────────────────────────────────────
// Extrai códigos de funcionários do HTML dentro do CDATA.
// CORRIGIDO: regex busca atributo 'codigo' em qualquer posição
// dentro da tag <tr>, independente da ordem dos atributos.
// Equivale ao BeautifulSoup row.get('codigo') do Flask.
// ─────────────────────────────────────────────

const xmlString = $input.first().json.xml_ref;

// Extrai conteúdo do CDATA
const cdataMatch = xmlString.match(/<!\[CDATA\[([\s\S]*?)\]\]>/);
if (!cdataMatch) {
  throw new Error('No CDATA section found in the provided XML.');
}

const htmlContent = cdataMatch[1].trim();

// Busca todas as tags <tr> com class="table-row-body" que tenham atributo codigo
// Ordem dos atributos não importa — funciona com codigo antes ou depois de class
const trRegex = /<tr\b[^>]*\bclass="table-row-body"[^>]*\bcodigo="([^"]+)"[^>]*>/gi;
const trRegexAlt = /<tr\b[^>]*\bcodigo="([^"]+)"[^>]*\bclass="table-row-body"[^>]*>/gi;

const codes = [];
const seen  = new Set();

for (const regex of [trRegex, trRegexAlt]) {
  let match;
  while ((match = regex.exec(htmlContent)) !== null) {
    const codigo = match[1].trim();
    if (codigo && !seen.has(codigo)) {
      seen.add(codigo);
      codes.push({ codigo });
    }
  }
}

if (codes.length === 0) {
  throw new Error('No table rows with class "table-row-body" and codigo attribute found.');
}

console.log(JSON.stringify({
  timestamp   : new Date().toISOString(),
  route       : 'employers_plus',
  event       : 'codes_extracted',
  codes_count : codes.length,
  level       : 'info'
}));

return { ids: codes };

// HTTP 200 — preserva compatibilidade com Flask
const data = $input.first().json;

return {
  statusCode: 200,
  body: {
    message : 'Employee codes extracted successfully.',
    ids     : data.ids
  }
};

// Erro de validação ou extração
const input = $input.first().json;

console.log(JSON.stringify({
  timestamp : new Date().toISOString(),
  route     : 'employers_plus',
  event     : 'error',
  message   : input.message || input.error || 'Unknown error',
  level     : 'error'
}));

return {
  statusCode: input.statusCode || 400,
  body      : input.body || { ok: false, error: input.message || 'Validation or extraction failed' }
};
